using Contoso.Services;

namespace Contoso.Services.Tests;

[TestClass]
public sealed class ServiceRegistryTests
{
    private ServiceRegistry _registry = null!;

    [TestInitialize]
    public void Setup() => _registry = new ServiceRegistry();

    [TestMethod]
    public void Register_AndResolve_ReturnsSameInstance()
    {
        var service = new FakeLogger();

        _registry.Register<ILogger>(service);
        var resolved = _registry.Resolve<ILogger>();

        Assert.AreSame(service, resolved);
    }

    [TestMethod]
    public void Resolve_Unregistered_ReturnsNull()
    {
        var result = _registry.Resolve<ILogger>();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void ResolveRequired_Unregistered_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _registry.ResolveRequired<ILogger>());
    }

    [TestMethod]
    public void Register_OverwritesPreviousRegistration()
    {
        var first = new FakeLogger();
        var second = new FakeLogger();

        _registry.Register<ILogger>(first);
        _registry.Register<ILogger>(second);

        Assert.AreSame(second, _registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Clear_RemovesAllRegistrations()
    {
        _registry.Register<ILogger>(new FakeLogger());
        _registry.Register<ICache>(new FakeCache());

        _registry.Clear();

        Assert.IsNull(_registry.Resolve<ILogger>());
        Assert.IsNull(_registry.Resolve<ICache>());
    }

    [TestMethod]
    public void Remove_UnregistersService()
    {
        _registry.Register<ILogger>(new FakeLogger());

        _registry.Remove<ILogger>();

        Assert.IsNull(_registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Remove_LeavesOtherRegistrationsIntact()
    {
        var cache = new FakeCache();
        _registry.Register<ILogger>(new FakeLogger());
        _registry.Register<ICache>(cache);

        _registry.Remove<ILogger>();

        Assert.IsNotNull(_registry.Resolve<ICache>());
        Assert.AreSame(cache, _registry.Resolve<ICache>());
    }

    [TestMethod]
    public void GetAll_ReturnsAllRegisteredServices()
    {
        var logger = new FakeLogger();
        var cache = new FakeCache();
        _registry.Register<ILogger>(logger);
        _registry.Register<ICache>(cache);

        var all = _registry.GetAll();

        Assert.AreEqual(2, all.Count);
        CollectionAssert.Contains(all.ToList(), logger);
        CollectionAssert.Contains(all.ToList(), cache);
    }

    [TestMethod]
    public void Register_NullService_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _registry.Register<ILogger>(null!));
    }

    // Test doubles
    private interface ILogger { }
    private interface ICache { }
    private sealed class FakeLogger : ILogger { }
    private sealed class FakeCache : ICache { }
}

